// A simplified Quarkus extension build step.
// This runs during 'mvn package', NOT at app startup.
public class GreetingProcessor {

    @BuildStep
    FeatureBuildItem feature() {
        return new FeatureBuildItem("greeting");
    }

    // Records bytecode that will execute at static-init time.
    @BuildStep
    @Record(ExecutionTime.STATIC_INIT)
    BeanContainerBuildItem configure(GreetingRecorder recorder,
                                     GreetingConfig config) {
        recorder.configureGreeting(config.message());
        return new BeanContainerBuildItem();
    }
}

@Recorder
public class GreetingRecorder {
    public void configureGreeting(String message) {
        // Code captured here is replayed; it is the 'output' of build.
        GreetingHolder.MESSAGE = message;
    }
}

@ApplicationScoped
public class PricingService {

    private final TaxClient taxClient;

    // Constructor injection is preferred and fully supported.
    @Inject
    public PricingService(TaxClient taxClient) {
        this.taxClient = taxClient;
    }

    public BigDecimal priceWithTax(BigDecimal net, String region) {
        return net.add(taxClient.taxFor(net, region));
    }
}

