@Path("/orders")
public class OrderResource {

    @Inject OrderRepository repo;

    // Non-blocking: returns a Uni, runs on the event loop.
    @GET
    @Path("/{id}")
    public Uni<Order> get(@RestPath Long id) {
        return repo.findById(id)
                   .onItem().ifNull().failWith(NotFoundException::new);
    }

    // Streaming many items as Server-Sent Events.
    @GET
    @Path("/stream")
    @RestStreamElementType(MediaType.APPLICATION_JSON)
    public Multi<Order> stream() {
        return repo.streamAll();
    }

    // Explicitly blocking work is offloaded to a worker thread.
    @POST
    @Blocking
    public Order create(Order o) {
        return legacyBlockingService.persist(o);
    }
}

// Active-record style: public fields + static finders.
@Entity
public class Product extends PanacheEntity {  // gives you 'id' for free
    public String sku;
    public BigDecimal price;
    public boolean active;

    public static List<Product> findActiveBySku(String sku) {
        // Named, parameterized query; safe against injection.
        return list("active = true and sku = ?1", sku);
    }
}

// Usage reads almost like a DSL:
Product p = Product.findById(42L);
long cheap = Product.count("price < ?1", new BigDecimal("9.99"));
Product.update("active = false where price = 0");

// Repository style: better for testability and DI seams.
@ApplicationScoped
public class OrderRepository implements PanacheRepository<Order> {

    public List<Order> recentFor(Long customerId, int limit) {
        return find("customerId = ?1 order by createdAt desc", customerId)
                .page(0, limit)
                .list();
    }
}

// Quarkus Lambda handler — same business logic, native-compiled.
public class FraudHandler implements RequestHandler<ScoreRequest, ScoreResponse> {

    @Inject FraudScorer scorer;   // Arc injects at build-resolved wiring

    @Override
    public ScoreResponse handleRequest(ScoreRequest req, Context ctx) {
        double risk = scorer.score(req.features());
        return new ScoreResponse(risk, risk > 0.8 ? "DECLINE" : "ALLOW");
    }
}

// DTO populated by a reflective library (e.g. a custom mapper).
// Works on JVM, fails (empty fields) in native unless registered.
@RegisterForReflection
public class ScoreRequest {
    public double[] features;
    public String correlationId;
}

