@Path("/customers")
@Produces(MediaType.APPLICATION_JSON)
public class CustomerResource {

    @Inject CustomerRepository customers;
    @Inject OrderRepository orders;

    @GET
    @Path("/{id}/summary")
    public Uni<CustomerSummary> summary(@RestPath Long id) {
        Uni<Customer> customerUni = customers.findById(id)
            .onItem().ifNull()
                .failWith(() -> new NotFoundException("customer " + id));

        Uni<List<Order>> ordersUni = orders.recentFor(id, 10);

        // Run both concurrently, then combine without blocking.
        return Uni.combine().all().unis(customerUni, ordersUni)
            .asTuple()
            .onItem().transform(t -> {
                Customer c = t.getItem1();
                List<Order> recent = t.getItem2();
                BigDecimal total = recent.stream()
                    .map(Order::getAmount)
                    .reduce(BigDecimal.ZERO, BigDecimal::add);
                return new CustomerSummary(c.id, c.name, recent.size(), total);
            });
    }
}

@ApplicationScoped
class CustomerRepository implements PanacheRepositoryBase<Customer, Long> {}

@ApplicationScoped
class OrderRepository implements PanacheRepositoryBase<Order, Long> {
    Uni<List<Order>> recentFor(Long customerId, int limit) {
        return find("customerId = ?1 order by createdAt desc", customerId)
                .page(0, limit).list();
    }
}

// 1. DTO you own: annotate it directly.
@RegisterForReflection
public class ScoreRequest {
    public double[] features;
    public String correlationId;
}

// 2. Third-party class you cannot annotate: register via targets.
@RegisterForReflection(targets = { com.vendor.sdk.Token.class })
public class ReflectionConfig {
    // empty marker class; existence registers the targets at build time
}

// 3. Native integration test that exercises the reflective path.
//    Runs against the built artifact (native when -Dnative is set).
@QuarkusIntegrationTest
class ScoreReflectionIT {

    @Test
    void requestIsFullyPopulatedInNative() {
        ScoreRequest req =
            given()
                .contentType("application/json")
                .body("{\"features\":[0.1,0.9],\"correlationId\":\"abc\"}")
            .when()
                .post("/score/echo")
            .then()
                .statusCode(200)
                .extract().as(ScoreRequest.class);

        assertArrayEquals(new double[]{0.1, 0.9}, req.features);
        assertEquals("abc", req.correlationId); // would be null if unregistered
    }
}
